// Solution
function getMax(arr: any[]): number {
  let max = -Infinity;
  for (let i = 0; i < arr.length; i++) {
    if (typeof arr[i] === 'number') {
      max = Math.max(max, arr[i]);
    }
  }
  return max === -Infinity ? 'No maximum value' : max;
}

