class Solution:
  def getMax(self, arr: list) -> float:
    max_val = float('-inf');
    for item in arr:
      if isinstance(item, (int, float)):
        max_val = max(max_val, item);
    return max_val if max_val != float('-inf') else 'No maximum value';
